UPDATE curriculum_readings SET passage_content = '{"paragraphs": ["People have *morning* *routines*. In *Saudi* Arabia, they wake up early. They eat *breakfast*. They drink tea or *coffee*. Some eat bread and cheese too.", "Some people *exercise*. They run or walk in the park. Others read or *study* first. A good *routine* helps you feel happy. It helps you feel ready too.", "Each person has a new day. Some work in an office. Others work at home. A good *morning* start is very nice. What is your *routine*?"]}'::jsonb, passage_word_count = 79, updated_at = NOW() WHERE id = 'fea17f39-b8f2-4209-a26b-cf28bbf4e19e' RETURNING id, reading_label;